309→/**
310→ * 提取平台 Cookie
311→ */
312→private fun tryExtractCookies(
313→    platform: VideoPlatform,
314→    url: String,
315→    onResult: (PlatformCookies) -> Unit
316→) {
317→    val cookieManager = CookieManager.getInstance()
318→    val cookies = cookieManager.getCookie(url)
319→        ?: cookieManager.getCookie("https://www.${platform.cookieDomain}")
320→
321→    val cookieMap = mutableMapOf<String, String>()
322→    val cookiePairs = mutableListOf<Pair<String, String>>()
323→
324→    // 解析Cookie字符串
325→    cookies?.split(";")?.forEach { cookie ->
326→        val trimmed = cookie.trim()
327→        val parts = trimmed.split("=", limit = 2)
328→        if (parts.size == 2) {
329→            val key = parts[0].trim()
330→            val value = parts[1].trim()
331→            cookiePairs.add(Pair(key, value))
332→
333→            // 提取关键字段
334→            if (platform.cookieKeys.contains(key)) {
335→                cookieMap[key] = value
336→            }
337→        }
338→    }
339→
340→    // 构建完整Cookie字符串
341→    val fullCookie = cookiePairs.joinToString("; ") { (key, value) -> "$key=$value" }
342→
343→    Log.d("PlatformLoginDialog", "Extracted ${cookieMap.size}/${platform.cookieKeys.size} key cookies for $platform, total: ${cookiePairs.size}")
344→
345→    onResult(PlatformCookies(platform, cookieMap, fullCookie))
346→}
